/// method parameter along its "value"
@dynamicMemberLookup
struct ServiceParameterValue {
    enum Value {
        /// parameter that need to be provided by user at resolution time
        case runtime
        /// parameter whose value can be resolved using a service
        case service(Service)
    }

    let methodParameter: MethodParameter
    let value: Value

    var isRuntime: Bool {
        switch value {
            case .runtime:
                return true
            default:
